/**
 * Test case to demonstrate late data side output handling for session windows.
 *
 * This test verifies that late-arriving data is properly emitted to side output
 * when using session windows with sideOutputLateData configured.
 *
 * Scenario:
 * - Session windows with gap = 3 seconds
 * - Allowed lateness = 0 seconds
 * - Element 1 (timestamp 1000): Creates window [1000-1003]
 * - Watermark advances to 1004 (window [1000-1003] becomes late and is cleaned up)
 * - Element 2 (timestamp 1000): Arrives late (1000 + 0 = 1000 <= 1004, so it's late)
 * - Expected: Element 2 should be emitted to the late data side output, not processed as a new window
 */

@Test
@SuppressWarnings("unchecked")
void testSessionWindowsLateDataSideOutputIsEmitted() throws Exception {
    final int gapSize = 3;
    final long lateness = 0;

    ReducingStateDescriptor<Tuple2<String, Integer>> stateDesc =
            new ReducingStateDescriptor<>(
                    "window-contents",
                    new SumReducer(),
                    STRING_INT_TUPLE.createSerializer(new SerializerConfigImpl()));

    WindowOperatorFactory<
                    String,
                    Tuple2<String, Integer>,
                    Tuple2<String, Integer>,
                    Tuple3<String, Long, Long>,
                    TimeWindow>
            operator =
                    new WindowOperatorFactory<>(
                            EventTimeSessionWindows.withGap(Duration.ofSeconds(gapSize)),
                            new TimeWindow.Serializer(),
                            new TupleKeySelector(),
                            BasicTypeInfo.STRING_TYPE_INFO.createSerializer(
                                    new SerializerConfigImpl()),
                            stateDesc,
                            new InternalSingleValueWindowFunction<>(
                                    new ReducedSessionWindowFunction()),
                            EventTimeTrigger.create(),
                            lateness,
                            lateOutputTag); // Configure side output for late data

    OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple3<String, Long, Long>>
            testHarness = createTestHarness(operator);

    testHarness.open();

    ConcurrentLinkedQueue<Object> expected = new ConcurrentLinkedQueue<>();
    ConcurrentLinkedQueue<Object> lateExpected = new ConcurrentLinkedQueue<>();

    // Element 1: Create a session window [1000-1003]
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key2", 1), 1000));

    // Advance watermark to 1004, which closes the window [1000-1003]
    // (since 1003 + 0 = 1003 <= 1004)
    testHarness.processWatermark(new Watermark(1004));

    expected.add(new StreamRecord<>(new Tuple3<>("key2-1", 1000L, 1003L), 1002));
    expected.add(new Watermark(1004));

    // Element 2: Arrives at timestamp 1000 when watermark is at 1004
    // This element is LATE because 1000 + 0 = 1000 <= 1004
    // It should be side-outputted as late data, NOT processed as a new window
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key2", 2), 1000));

    // Expected: Element 2 should appear in the late data side output
    lateExpected.add(new StreamRecord<>(new Tuple2<>("key2", 2), 1000));

    testHarness.processWatermark(new Watermark(2000));
    expected.add(new Watermark(2000));

    ConcurrentLinkedQueue<Object> actual = testHarness.getOutput();
    ConcurrentLinkedQueue<StreamRecord<Tuple2<String, Integer>>> lateActual =
            testHarness.getSideOutput(lateOutputTag);

    TestHarnessUtil.assertOutputEqualsSorted(
            "Output was not correct.",
            expected,
            actual,
            new Tuple2ResultSortComparator());

    TestHarnessUtil.assertOutputEqualsSorted(
            "Late data side output was not correct.",
            lateExpected,
            (Iterable) lateActual,
            new Tuple2ResultSortComparator());

    testHarness.close();
}

// FIXED VERSION of processElement method
// The fix ensures that for merging windows, late elements are side-outputted immediately
// if lateDataOutputTag is configured, rather than waiting to see if they can be added to windows.

@Override
public void processElement(StreamRecord<IN> element) throws Exception {
    final Collection<W> elementWindows =
            windowAssigner.assignWindows(
                    element.getValue(), element.getTimestamp(), windowAssignerContext);

    // if element is handled by none of assigned elementWindows
    boolean isSkippedElement = true;

    final K key = this.<K>getKeyedStateBackend().getCurrentKey();

    if (windowAssigner instanceof MergingWindowAssigner) {
        MergingWindowSet<W> mergingWindows = getMergingWindowSet();

        // For merging windows, check if element is late BEFORE attempting to process it.
        // If the element is late and side output is configured, emit it immediately
        // and skip processing in this branch.
        if (isElementLate(element)) {
            if (lateDataOutputTag != null) {
                sideOutput(element);
            } else {
                this.numLateRecordsDropped.inc();
            }
            isSkippedElement = true;
        } else {
            // Element is not late, proceed with normal merging window processing
            for (W window : elementWindows) {

                // adding the new window might result in a merge, in that case the actualWindow
                // is the merged window and we work with that. If we don't merge then
                // actualWindow == window
                W actualWindow =
                        mergingWindows.addWindow(
                                window,
                                new MergingWindowSet.MergeFunction<W>() {
                                    @Override
                                    public void merge(
                                            W mergeResult,
                                            Collection<W> mergedWindows,
                                            W stateWindowResult,
                                            Collection<W> mergedStateWindows)
                                            throws Exception {

                                        if ((windowAssigner.isEventTime()
                                                && mergeResult.maxTimestamp() + allowedLateness
                                                        <= internalTimerService
                                                                .currentWatermark())) {
                                            throw new UnsupportedOperationException(
                                                    "The end timestamp of an "
                                                            + "event-time window cannot become earlier than the current watermark "
                                                            + "by merging. Current watermark: "
                                                            + internalTimerService
                                                                    .currentWatermark()
                                                            + " window: "
                                                            + mergeResult);
                                        } else if (!windowAssigner.isEventTime()) {
                                            long currentProcessingTime =
                                                    internalTimerService.currentProcessingTime();
                                            if (mergeResult.maxTimestamp()
                                                    <= currentProcessingTime) {
                                                throw new UnsupportedOperationException(
                                                        "The end timestamp of a "
                                                                + "processing-time window cannot become earlier than the current processing time "
                                                                + "by merging. Current processing time: "
                                                                + currentProcessingTime
                                                                + " window: "
                                                                + mergeResult);
                                            }
                                        }

                                        triggerContext.key = key;
                                        triggerContext.window = mergeResult;

                                        triggerContext.onMerge(mergedWindows);

                                        for (W m : mergedWindows) {
                                            triggerContext.window = m;
                                            triggerContext.clear();
                                            deleteCleanupTimer(m);
                                        }

                                        // merge the merged state windows into the newly resulting
                                        // state window
                                        windowMergingState.mergeNamespaces(
                                                stateWindowResult, mergedStateWindows);
                                    }
                                });

                // drop if the window is already late
                if (isWindowLate(actualWindow)) {
                    mergingWindows.retireWindow(actualWindow);
                    continue;
                }
                isSkippedElement = false;

                W stateWindow = mergingWindows.getStateWindow(actualWindow);
                if (stateWindow == null) {
                    throw new IllegalStateException(
                            "Window " + window + " is not in in-flight window set.");
                }

                windowState.setCurrentNamespace(stateWindow);
                windowState.add(element.getValue());

                triggerContext.key = key;
                triggerContext.window = actualWindow;

                TriggerResult triggerResult = triggerContext.onElement(element);

                if (triggerResult.isFire()) {
                    ACC contents = windowState.get();
                    if (contents != null) {
                        emitWindowContents(actualWindow, contents);
                    }
                }

                if (triggerResult.isPurge()) {
                    windowState.clear();
                }
                registerCleanupTimer(actualWindow);
            }

            // need to make sure to update the merging state in state
            mergingWindows.persist();
        }
    } else {
        for (W window : elementWindows) {

            // drop if the window is already late
            if (isWindowLate(window)) {
                continue;
            }
            isSkippedElement = false;

            windowState.setCurrentNamespace(window);
            windowState.add(element.getValue());

            triggerContext.key = key;
            triggerContext.window = window;

            TriggerResult triggerResult = triggerContext.onElement(element);

            if (triggerResult.isFire()) {
                ACC contents = windowState.get();
                if (contents != null) {
                    emitWindowContents(window, contents);
                }
            }

            if (triggerResult.isPurge()) {
                windowState.clear();
            }
            registerCleanupTimer(window);
        }
    }

    // side output input event if
    // element not handled by any window
    // late arriving tag has been set
    // windowAssigner is event time and current timestamp + allowed lateness no less than
    // element timestamp
    // NOTE: For merging windows, this is now redundant for truly late elements,
    // since they're handled above. But we keep it for non-merging windows
    // and for edge cases where isSkippedElement might still be true.
    if (isSkippedElement && isElementLate(element)) {
        if (lateDataOutputTag != null) {
            sideOutput(element);
        } else {
            this.numLateRecordsDropped.inc();
        }
    }
}

