81: /**
82:  * An operator that implements the logic for windowing based on a {@link WindowAssigner} and {@link
83:  * Trigger}.
84:  *
85:  * <p>When an element arrives it gets assigned a key using a {@link KeySelector} and it gets
86:  * assigned to zero or more windows using a {@link WindowAssigner}. Based on this, the element is
87:  * put into panes. A pane is the bucket of elements that have the same key and same {@code Window}.
88:  * An element can be in multiple panes if it was assigned to multiple windows by the {@code
89:  * WindowAssigner}.
90:  *
91:  * <p>Each pane gets its own instance of the provided {@code Trigger}. This trigger determines when
92:  * the contents of the pane should be processed to emit results. When a trigger fires, the given
93:  * {@link InternalWindowFunction} is invoked to produce the results that are emitted for the pane to
94:  * which the {@code Trigger} belongs.
95:  *
96:  * @param <K> The type of key returned by the {@code KeySelector}.
97:  * @param <IN> The type of the incoming elements.
98:  * @param <OUT> The type of elements emitted by the {@code InternalWindowFunction}.
99:  * @param <W> The type of {@code Window} that the {@code WindowAssigner} assigns.
100:  */
101: @Internal
102: public class WindowOperator<K, IN, ACC, OUT, W extends Window>
103:         extends AbstractUdfStreamOperator<OUT, InternalWindowFunction<ACC, OUT, K, W>>
104:         implements OneInputStreamOperator<IN, OUT>, Triggerable<K, W> {
105: 
106:     private static final long serialVersionUID = 1L;
107: 
108:     // ------------------------------------------------------------------------
109:     // Configuration values and user functions
110:     // ------------------------------------------------------------------------
111: 
112:     protected final WindowAssigner<? super IN, W> windowAssigner;
113: 
114:     private final KeySelector<IN, K> keySelector;
115: 
116:     private final Trigger<? super IN, ? super W> trigger;
117: 
118:     private final StateDescriptor<? extends AppendingState<IN, ACC>, ?> windowStateDescriptor;
119: 
120:     /** For serializing the key in checkpoints. */
121:     protected final TypeSerializer<K> keySerializer;
122: 
123:     /** For serializing the window in checkpoints. */
124:     protected final TypeSerializer<W> windowSerializer;
125: 
126:     /**
127:      * The allowed lateness for elements. This is used for:
128:      *
129:      * <ul>
130:      *   <li>Deciding if an element should be dropped from a window due to lateness.
131:      *   <li>Clearing the state of a window if the system time passes the {@code window.maxTimestamp
132:      *       + allowedLateness} landmark.
133:      * </ul>
134:      */
135:     protected final long allowedLateness;
136: 
137:     /**
138:      * {@link OutputTag} to use for late arriving events. Elements for which {@code
139:      * window.maxTimestamp + allowedLateness} is smaller than the current watermark will be emitted
140:      * to this.
141:      */
142:     protected final OutputTag<IN> lateDataOutputTag;
143: 
144:     private static final String LATE_ELEMENTS_DROPPED_METRIC_NAME = "numLateRecordsDropped";
145: 
146:     protected transient Counter numLateRecordsDropped;
