277:     public void onEventTime(InternalTimer<K, W> timer) throws Exception {
278: 
279:         triggerContext.key = timer.getKey();
280:         triggerContext.window = timer.getNamespace();
281:         evictorContext.key = timer.getKey();
282:         evictorContext.window = timer.getNamespace();
283: 
284:         MergingWindowSet<W> mergingWindows = null;
285: 
286:         if (windowAssigner instanceof MergingWindowAssigner) {
287:             mergingWindows = getMergingWindowSet();
288:             W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
289:             if (stateWindow == null) {
290:                 // Timer firing for non-existent window, this can only happen if a
291:                 // trigger did not clean up timers. We have already cleared the merging
292:                 // window and therefore the Trigger state, however, so nothing to do.
293:                 return;
294:             } else {
295:                 evictingWindowState.setCurrentNamespace(stateWindow);
296:             }
297:         } else {
298:             evictingWindowState.setCurrentNamespace(triggerContext.window);
299:         }
