{"content":"150:      *     {@code Window} itself in case no merge occurred.
151:      * @throws Exception
152:      */
153:     public W addWindow(W newWindow, MergeFunction<W> mergeFunction) throws Exception {
154: 
155:         List<W> windows = new ArrayList<>();
156: 
157:         windows.addAll(this.mapping.keySet());
158:         windows.add(newWindow);
159: 
160:         final Map<W, Collection<W>> mergeResults = new HashMap<>();
161:         windowAssigner.mergeWindows(
162:                 windows,
163:                 new MergingWindowAssigner.MergeCallback<W>() {
164:                     @Override
165:                     public void merge(Collection<W> toBeMerged, W mergeResult) {
166:                         if (LOG.isDebugEnabled()) {
167:                             LOG.debug("Merging {} into {}", toBeMerged, mergeResult);
168:                         }
169:                         mergeResults.put(mergeResult, toBeMerged);
170:                     }
171:                 });
172: 
173:         W resultWindow = newWindow;
174:         boolean mergedNewWindow = false;
175: 
176:         // perform the merge
177:         for (Map.Entry<W, Collection<W>> c : mergeResults.entrySet()) {
178:             W mergeResult = c.getKey();
179:             Collection<W> mergedWindows = c.getValue();
180: 
181:             // if our new window is in the merged windows make the merge result the
182:             // result window
183:             if (mergedWindows.remove(newWindow)) {
184:                 mergedNewWindow = true;
185:                 resultWindow = mergeResult;
186:             }
187: 
188:             // pick any of the merged windows and choose that window's state window
189:             // as the state window for the merge result
190:             W mergedStateWindow = this.mapping.get(mergedWindows.iterator().next());
191: 
192:             // figure out the state windows that we are merging
193:             List<W> mergedStateWindows = new ArrayList<>();
194:             for (W mergedWindow : mergedWindows) {
195:                 W res = this.mapping.remove(mergedWindow);
196:                 if (res != null) {
197:                     mergedStateWindows.add(res);
198:                 }
199:             }
200: 
201:             this.mapping.put(mergeResult, mergedStateWindow);
202: 
203:             // don't put the target state window into the merged windows
204:             mergedStateWindows.remove(mergedStateWindow);
205: 
206:             // don't merge the new window itself, it never had any state associated with it
207:             // i.e. if we are only merging one pre-existing window into itself
208:             // without extending the pre-existing window
209:             if (!(mergedWindows.contains(mergeResult) && mergedWindows.size() == 1)) {
210:                 mergeFunction.merge(
211:                         mergeResult,
212:                         mergedWindows,
213:                         this.mapping.get(mergeResult),
214:                         mergedStateWindows);
215:             }
216:         }
217: 
218:         // the new window created a new, self-contained window without merging
219:         if (mergeResults.isEmpty() || (resultWindow.equals(newWindow) && !mergedNewWindow)) {
220:             this.mapping.put(resultWindow, resultWindow);
221:         }
222: 
223:         return resultWindow;
224:     }
