227:      * Callback for {@link #addWindow(Window, MergeFunction)}.
228:      *
229:      * @param <W>
230:      */
231:     public interface MergeFunction<W> {
232: 
233:         /**
234:          * This gets called when a merge occurs.
235:          *
236:          * @param mergeResult The newly resulting merged {@code Window}.
237:          * @param mergedWindows The merged {@code Window Windows}.
238:          * @param stateWindowResult The state window of the merge result.
239:          * @param mergedStateWindows The merged state windows.
240:          * @throws Exception
241:          */
242:         void merge(
243:                 W mergeResult,
244:                 Collection<W> mergedWindows,
245:                 W stateWindowResult,
246:                 Collection<W> mergedStateWindows)
247:                 throws Exception;
248:     }
